def solve(nums: Array[Long], k: Long): Long = {
  import scala.collection.mutable.HashMap
  val dp = HashMap[Long, Long]()
  dp(0) = 0L  // Base case: sum 0 with remainder 0

  var prefixSum = 0L
  var minSum = Long.MaxValue

  for (num <- nums) {
    prefixSum += num
    val remainder = prefixSum % k

    // If the remainder is not in dp, we add it with the current prefix sum
    if (!dp.contains(remainder)) {
      dp(remainder) = prefixSum
    } else {
      dp(remainder) = math.min(dp(remainder), prefixSum)
    }

    // For each remainder, we can try to remove a subarray that ends at the current position
    // and has a sum divisible by k. So we look for the minimum sum that has the same remainder
    // as the current prefix sum.
    minSum = math.min(minSum, dp(remainder))
  }

  minSum
}
